import {
  type MouseEvent as ReactMouseEvent,
  useEffect,
  useMemo,
  useState,
} from 'react';
import { useIntl } from 'react-intl';

import type { ColorToken } from '../../../types/color-palette.js';
import type { Point } from '../../../types/point.js';
import { THRESHOLD_MESSAGES } from '../messages/messages.js';
import type { ThresholdMarker } from '../types.js';
import { groupOverlappingMarkers } from '../utils/group-overlapping-markers.js';

const TOOLTIP_Y_OFFSET = 22;

type tooltipItem = {
  id: string;
  name: string | string[];
  color: ColorToken;
  values: string[];
};

export function useThresholdBarTooltip(
  markers: ThresholdMarker[],
  onHover?: (id: string | undefined) => void,
) {
  const groupedMarkers = useMemo(
    () => groupOverlappingMarkers(markers),
    [markers],
  );
  const intl = useIntl();

  const [hoveredIndex, setHoveredIndex] = useState<number | undefined>();
  const [tooltipPosition, setTooltipPosition] = useState<Point>();
  const [tooltipItems, setTooltipItems] = useState<tooltipItem[]>([]);

  useEffect(() => {
    if (hoveredIndex === undefined) {
      return;
    }
    const onScroll = () => setHoveredIndex(undefined);
    window.addEventListener('scroll', onScroll, { once: true, capture: true });
    return () =>
      window.removeEventListener('scroll', onScroll, { capture: true });
  }, [hoveredIndex]);

  function handleMouseMove(event: ReactMouseEvent, index: number) {
    setHoveredIndex(index);

    const tooltipPosition = {
      x: event.clientX,
      y: event.clientY + TOOLTIP_Y_OFFSET,
    };
    const marker = markers[index];

    const belongingGroup = groupedMarkers.find((group) =>
      group.some((item) => {
        return item.y1 === marker.y1 && item.y0 === marker.y0;
      }),
    );

    if (belongingGroup) {
      const tooltipItems = belongingGroup
        .filter((item) => !item.isShadow)
        .map((item, index) => ({
          id: item.id,
          color: { Default: item.color },
          values: [item.value],
          name:
            item.label ?? intl.formatMessage(THRESHOLD_MESSAGES.thresholdLabel),
        }));

      setTooltipPosition(tooltipPosition);
      setTooltipItems(tooltipItems);
      onHover?.(marker.id);
    }
  }

  function handleMouseLeave() {
    setHoveredIndex(undefined);
    setTooltipItems([]);
    onHover?.(undefined);
  }

  return {
    showTooltip: hoveredIndex !== undefined && tooltipPosition,
    tooltipPosition,
    tooltipItems,
    handleMouseMove,
    handleMouseLeave,
  };
}
